using System.ComponentModel;
using System.Text.Json;
using ModelContextProtocol.Server;

[McpServerResourceType]
public static class ConfigResources
{
    private static readonly Dictionary<string, string> AppConfig = new()
    {
        ["app:name"] = "ConfigMcpServer",
        ["app:version"] = "1.0.0",
        ["app:environment"] = "Development",
        ["feature:dark_mode"] = "true",
        ["feature:beta_access"] = "false",
    };

    [McpServerResource(
        UriTemplate = "config://app/all",
        Name = "All Configuration",
        MimeType = "application/json"),
     Description("Returns all application configuration as JSON.")]
    public static string GetAllConfig() =>
        JsonSerializer.Serialize(AppConfig, new JsonSerializerOptions { WriteIndented = true });

    [McpServerResource(
        UriTemplate = "config://app/{key}",
        Name = "Configuration Value",
        MimeType = "text/plain"),
     Description("Returns a single configuration value by key.")]
    public static string GetConfigValue(string key) =>
        AppConfig.TryGetValue(key, out var value) ? value : $"Key '{key}' not found";

    /// <summary>Allows tools to read/write config at runtime.</summary>
    internal static string? TryGet(string key) =>
        AppConfig.TryGetValue(key, out var v) ? v : null;

    internal static void Set(string key, string value) =>
        AppConfig[key] = value;
}

using System.ComponentModel;
using ModelContextProtocol.Server;

[McpServerToolType]
public static class ConfigTools
{
    [McpServerTool, Description("Get a configuration value by its key.")]
    public static string GetConfig(
        [Description("The configuration key, e.g. 'app:name'")] string key)
    {
        var value = ConfigResources.TryGet(key);
        return value is not null
            ? $"{key} = {value}"
            : $"Key '{key}' not found.";
    }

    [McpServerTool, Description("Set a configuration value. Creates the key if it doesn't exist.")]
    public static string SetConfig(
        [Description("The configuration key")] string key,
        [Description("The new value to store")] string value)
    {
        ConfigResources.Set(key, value);
        return $"Updated {key} = {value}";
    }

    [McpServerTool, Description("List all available configuration keys.")]
    public static string ListConfigKeys()
    {
        var allConfig = System.Text.Json.JsonSerializer.Deserialize<Dictionary<string, string>>(
            ConfigResources.GetAllConfig());
        return string.Join("\n", allConfig!.Keys.Order());
    }
}

