+using System.ComponentModel;
+using ModelContextProtocol.Server;
+
+[McpServerToolType]
+public static class ConfigTools
+{
+    [McpServerTool, Description("Get a configuration value by its key.")]
+    public static string GetConfig(
+        [Description("The configuration key, e.g. 'app:name'")] string key)
+    {
+        var value = ConfigResources.TryGet(key);
+        return value is not null
+            ? $"{key} = {value}"
+            : $"Key '{key}' not found.";
+    }
+
+    [McpServerTool, Description("Set a configuration value. Creates the key if it doesn't exist.")]
+    public static string SetConfig(
+        [Description("The configuration key")] string key,
+        [Description("The new value to store")] string value)
+    {
+        ConfigResources.Set(key, value);
+        return $"Updated {key} = {value}";
+    }
+
+    [McpServerTool, Description("List all available configuration keys.")]
+    public static string ListConfigKeys()
+    {
+        var allConfig = System.Text.Json.JsonSerializer.Deserialize<Dictionary<string, string>>(
+            ConfigResources.GetAllConfig());
+        return string.Join("\n", allConfig!.Keys.Order());
+    }
+}
